// Change this value to test another branch: refund, account_access, technical, account_deletion, sales, complaint, security, unclear.
const TEST_CASE = 'sales';

const cases = {
  refund: ['TCK-MOCK-REFUND', 'email', 'Charged twice for my subscription', 'I was charged twice this month and I want the duplicate payment refunded. This is frustrating.'],
  account_access: ['TCK-MOCK-LOGIN', 'chat', 'Cannot log in after password reset', 'I reset my password but the login page still says the code is expired. Please help me access my account.'],
  technical: ['TCK-MOCK-API', 'form', 'API returns 500 errors', 'Our test integration has returned 500 errors for the last 20 minutes. The status page looks normal.'],
  account_deletion: ['TCK-MOCK-DELETE', 'email', 'Delete my account', 'Please delete my account and all stored data. I do not want to use the service anymore.'],
  sales: ['TCK-MOCK-SALES', 'email', 'Question about team pricing', 'Can you explain the price difference between starter and team plans for 12 users?'],
  complaint: ['TCK-MOCK-COMPLAINT', 'social', 'This is unacceptable', 'Your app broke again during our client meeting. I am angry and need a manager to contact me today.'],
  security: ['TCK-MOCK-SECURITY', 'email', 'Suspicious login email', 'I received a login alert from a city I have never visited. Please secure my account.'],
  unclear: ['TCK-MOCK-UNCLEAR', 'form', 'Need help', 'It is not working and I am not sure what happened.'],
};

const selected = cases[TEST_CASE] || cases.refund;

return [{
  json: {
    ticket_id: selected[0],
    created_at: '2026-05-19T10:00:00Z',
    customer_name: 'Mock Customer',
    customer_email: 'mock.customer@example.com',
    subject: selected[2],
    message: selected[3],
    channel: selected[1],
    status: 'new',
    processed: '',
    account_id: 'acct_mock_001',
    order_id: 'order_mock_001',
    locale: 'en-US',
    attachments_count: 0,
    row_number: 2,
  },
}];

const isProcessed = (value) => {
  if (value === true) return true;
  const normalized = String(value ?? '').trim().toLowerCase();
  return ['true', 'yes', '1', 'processed', 'done'].includes(normalized);
};

const text = (value) => String(value ?? '').trim();
const nowIso = () => new Date().toISOString();
const safeCompact = (value) => text(value).replace(/\s+/g, ' ').slice(0, 5000);
const hasAnyTicketSignal = (row) => ['ticket_id', 'created_at', 'channel', 'subject', 'message', 'customer_name', 'customer_email']
  .some((field) => text(row[field]));

const required = ['ticket_id', 'created_at', 'channel', 'subject', 'message'];
const out = [];
let skippedProcessed = 0;
let skippedEmpty = 0;

for (const [index, item] of items.entries()) {
  const row = item.json || {};

  if (!hasAnyTicketSignal(row)) {
    skippedEmpty += 1;
    continue;
  }

  if (isProcessed(row.processed)) {
    skippedProcessed += 1;
    continue;
  }

  const customer = row.customer || {};
  const ticket = {
    ticket_id: text(row.ticket_id),
    created_at: text(row.created_at),
    channel: text(row.channel),
    customer_name: text(row.customer_name || customer.name),
    customer_email: text(row.customer_email || customer.email),
    subject: safeCompact(row.subject),
    message: safeCompact(row.message),
    account_id: text(row.account_id),
    order_id: text(row.order_id),
    locale: text(row.locale || 'en-US'),
    attachments_count: Number(row.attachments_count || 0),
    source_row_number: row.row_number ?? row.rowNumber ?? row.__rowNumber ?? row._rowNumber ?? index + 2,
  };

  const validationErrors = [];
  for (const field of required) {
    if (!ticket[field]) validationErrors.push(`missing_${field}`);
  }

  const llmPayload = {
    ticket_id: ticket.ticket_id,
    created_at: ticket.created_at,
    channel: ticket.channel,
    subject: ticket.subject,
    message: ticket.message,
    account_id: ticket.account_id,
    order_id: ticket.order_id,
    locale: ticket.locale,
    attachments_count: ticket.attachments_count,
  };

  out.push({
    json: {
      ...ticket,
      has_work: true,
      processed_at: nowIso(),
      input_valid: validationErrors.length === 0,
      validation_errors: validationErrors,
      source_items_count: items.length,
      skipped_processed_count: skippedProcessed,
      skipped_empty_count: skippedEmpty,
      llm_payload: llmPayload,
      llm_prompt: `Classify this support ticket and return strict JSON only. Ticket: ${JSON.stringify(llmPayload)}`,
    },
  });
}

if (out.length === 0) {
  return [{
    json: {
      has_work: false,
      control_event: 'no_unprocessed_tickets',
      reason: 'No unprocessed support tickets were found.',
      source_items_count: items.length,
      skipped_processed_count: skippedProcessed,
      skipped_empty_count: skippedEmpty,
      checked_at: nowIso(),
    },
  }];
}

return out;

const lower = (value) => String(value ?? '').toLowerCase();
const contains = (text, words) => words.some((word) => text.includes(word));

function classify(ticket) {
  const text = `${lower(ticket.subject)} ${lower(ticket.message)}`;
  let output = {
    category: 'other',
    priority: 'normal',
    sentiment: 'neutral',
    summary: 'Customer needs support review.',
    routing_team: 'support_lead',
    needs_human_review: false,
    risk_flags: [],
    draft_reply: 'Thanks for contacting us. A support team member will review your message and follow up.',
    confidence: 0.78,
  };

  if (contains(text, ['charged twice', 'refund', 'duplicate payment', 'payment refunded'])) {
    output = {
      category: 'refund_request', priority: 'high', sentiment: contains(text, ['frustrating', 'angry', 'unacceptable']) ? 'angry' : 'worried',
      summary: 'Customer reports a duplicate charge and asks for refund review.', routing_team: 'billing', needs_human_review: true,
      risk_flags: ['refund', 'payment_issue'], draft_reply: 'Thanks for reporting this. I have prepared your payment issue for billing review before any refund action is taken.', confidence: 0.9,
    };
  } else if (contains(text, ['log in', 'login', 'password reset', 'code is expired', 'access my account'])) {
    output = {
      category: 'account_access', priority: 'high', sentiment: 'worried', summary: 'Customer cannot access the account after a password reset issue.',
      routing_team: 'account_support', needs_human_review: false, risk_flags: [], draft_reply: 'Thanks for the details. I have routed this to account support so the reset issue can be checked.', confidence: 0.88,
    };
  } else if (contains(text, ['500', 'api', 'outage', 'errors', 'status page'])) {
    output = {
      category: 'technical_issue', priority: 'urgent', sentiment: 'worried', summary: 'Customer reports repeated API errors while the status page appears normal.',
      routing_team: 'technical_support', needs_human_review: false, risk_flags: [], draft_reply: 'Thanks for reporting the API errors. I have routed this to technical support with the timing you provided.', confidence: 0.86,
    };
  } else if (contains(text, ['delete my account', 'delete account', 'stored data', 'do not want to use'])) {
    output = {
      category: 'cancellation', priority: 'high', sentiment: 'neutral', summary: 'Customer requests account deletion and removal of stored data.',
      routing_team: 'support_lead', needs_human_review: true, risk_flags: ['account_deletion', 'cancellation'], draft_reply: 'Thanks for contacting us. I have prepared your account deletion request for human review so the team can confirm the correct process.', confidence: 0.91,
    };
  } else if (contains(text, ['pricing', 'price difference', 'team plans', 'starter'])) {
    output = {
      category: 'sales_question', priority: 'normal', sentiment: 'neutral', summary: 'Customer asks about pricing or plan differences.',
      routing_team: 'sales', needs_human_review: false, risk_flags: [], draft_reply: 'Thanks for your interest. I have routed your pricing question to the sales team.', confidence: 0.92,
    };
  } else if (contains(text, ['unacceptable', 'angry', 'manager', 'client meeting'])) {
    output = {
      category: 'complaint', priority: 'urgent', sentiment: 'angry', summary: 'Customer is angry about a service failure and asks for manager contact.',
      routing_team: 'support_lead', needs_human_review: true, risk_flags: ['angry_customer', 'manager_requested'], draft_reply: 'I am sorry this happened. I have escalated your message for manager review so the team can follow up with the right context.', confidence: 0.89,
    };
  } else if (contains(text, ['suspicious login', 'secure my account', 'never visited', 'login alert'])) {
    output = {
      category: 'account_access', priority: 'urgent', sentiment: 'worried', summary: 'Customer reports a suspicious login alert and asks to secure the account.',
      routing_team: 'account_support', needs_human_review: true, risk_flags: ['security_issue'], draft_reply: 'Thanks for reporting the suspicious login alert. I have escalated this for account security review.', confidence: 0.93,
    };
  } else if (contains(text, ['not working', 'not sure what happened', 'need help'])) {
    output = {
      category: 'other', priority: 'normal', sentiment: 'unclear', summary: 'Customer says something is not working but does not provide enough detail.',
      routing_team: 'support_lead', needs_human_review: true, risk_flags: ['unclear_intent'], draft_reply: 'Thanks for reaching out. Could you share what you were trying to do, what happened, and any error message you saw?', confidence: 0.61,
    };
  }

  return output;
}

return items.map((item) => ({
  json: {
    ...item.json,
    llm_provider: 'mock_demo_classifier',
    llm_response_text: JSON.stringify(classify(item.json)),
  },
}));

const allowed = {
  category: ['billing', 'technical_issue', 'account_access', 'refund_request', 'cancellation', 'sales_question', 'complaint', 'other'],
  priority: ['low', 'normal', 'high', 'urgent'],
  sentiment: ['positive', 'neutral', 'worried', 'angry', 'unclear'],
  routing_team: ['billing', 'technical_support', 'account_support', 'sales', 'support_lead'],
  risk_flags: ['refund', 'payment_issue', 'account_deletion', 'legal_threat', 'security_issue', 'angry_customer', 'unclear_intent', 'low_llm_confidence', 'cancellation', 'manager_requested'],
};
const threshold = 0.75;
const text = (value) => String(value ?? '').trim();
const safeTelegram = (value) => text(value).replace(/[\u0000-\u001F\u007F]/g, ' ').replace(/[<>*_`\[\]()~#+\-=|{}.!]/g, ' ').replace(/\s+/g, ' ').slice(0, 700);

const fallback = (ticket, reason) => ({
  category: 'other', priority: 'high', sentiment: 'unclear', summary: 'Ticket requires manual triage because automated classification was not reliable.',
  routing_team: 'support_lead', needs_human_review: true, risk_flags: ['unclear_intent', 'low_llm_confidence'],
  draft_reply: 'Thanks for contacting us. A support team member will review your message and follow up.', confidence: 0,
  validation_status: 'fallback', fallback_reason: reason,
});

function normalizeFlags(flags) {
  const output = [];
  for (const flag of Array.isArray(flags) ? flags : []) {
    const normalized = text(flag);
    if (allowed.risk_flags.includes(normalized) && !output.includes(normalized)) output.push(normalized);
  }
  return output;
}

function validateObject(obj) {
  const errors = [];
  for (const field of ['category', 'priority', 'sentiment', 'summary', 'routing_team', 'needs_human_review', 'risk_flags', 'draft_reply', 'confidence']) {
    if (!(field in obj)) errors.push(`missing_${field}`);
  }
  if (!allowed.category.includes(obj.category)) errors.push('invalid_category');
  if (!allowed.priority.includes(obj.priority)) errors.push('invalid_priority');
  if (!allowed.sentiment.includes(obj.sentiment)) errors.push('invalid_sentiment');
  if (!allowed.routing_team.includes(obj.routing_team)) errors.push('invalid_routing_team');
  if (typeof obj.needs_human_review !== 'boolean') errors.push('invalid_needs_human_review');
  if (!Array.isArray(obj.risk_flags)) errors.push('invalid_risk_flags');
  if (typeof Number(obj.confidence) !== 'number' || Number.isNaN(Number(obj.confidence)) || Number(obj.confidence) < 0 || Number(obj.confidence) > 1) errors.push('invalid_confidence');
  return errors;
}

return items.map((item) => {
  const ticket = item.json;
  let parsed;
  let parseError = '';

  if (!ticket.input_valid) {
    parsed = fallback(ticket, `invalid_input:${(ticket.validation_errors || []).join(',')}`);
  } else {
    try {
      parsed = JSON.parse(text(ticket.llm_response_text));
    } catch (error) {
      parseError = error.message;
      parsed = fallback(ticket, 'invalid_llm_json');
    }

    const schemaErrors = parsed.validation_status === 'fallback' ? [] : validateObject(parsed);
    if (schemaErrors.length) parsed = fallback(ticket, `schema_error:${schemaErrors.join(',')}`);
  }

  const flags = new Set(normalizeFlags(parsed.risk_flags));
  const content = `${ticket.subject} ${ticket.message}`.toLowerCase();
  if (parsed.category === 'refund_request' || content.includes('refund')) flags.add('refund');
  if (content.includes('payment') || content.includes('charged') || content.includes('billing')) flags.add('payment_issue');
  if (content.includes('delete my account') || content.includes('delete account') || content.includes('stored data')) flags.add('account_deletion');
  if (content.includes('legal') || content.includes('lawyer') || content.includes('sue')) flags.add('legal_threat');
  if (content.includes('suspicious login') || content.includes('secure my account') || content.includes('security')) flags.add('security_issue');
  if (parsed.sentiment === 'angry' || content.includes('angry') || content.includes('unacceptable')) flags.add('angry_customer');
  if (parsed.sentiment === 'unclear' || parsed.category === 'other') flags.add('unclear_intent');
  if (parsed.category === 'cancellation') flags.add('cancellation');
  if (Number(parsed.confidence) < threshold) flags.add('low_llm_confidence');

  const riskyFlags = ['refund', 'payment_issue', 'account_deletion', 'legal_threat', 'security_issue', 'angry_customer', 'unclear_intent', 'low_llm_confidence', 'cancellation'];
  const needsHumanReview = Boolean(parsed.needs_human_review) || [...flags].some((flag) => riskyFlags.includes(flag));
  const reviewQueueRequired = needsHumanReview || ['high', 'urgent'].includes(parsed.priority);
  const riskFlags = [...flags];
  const reviewReason = reviewQueueRequired ? (riskFlags.length ? riskFlags.join(', ') : `priority_${parsed.priority}`) : '';
  const status = reviewQueueRequired ? 'human_review_required' : 'triaged';

  return {
    json: {
      ...ticket,
      category: parsed.category,
      priority: parsed.priority,
      sentiment: parsed.sentiment,
      summary: text(parsed.summary),
      routing_team: parsed.routing_team,
      needs_human_review: needsHumanReview,
      review_queue_required: reviewQueueRequired,
      risk_flags: riskFlags,
      risk_flags_text: riskFlags.join(', '),
      draft_reply: text(parsed.draft_reply),
      confidence: Number(parsed.confidence),
      status,
      review_reason: reviewReason,
      validation_status: parsed.validation_status || 'valid_llm_json',
      fallback_reason: parsed.fallback_reason || parseError,
      audit_message: reviewQueueRequired ? `Ticket routed for review: ${reviewReason || parsed.priority}` : `Ticket triaged to ${parsed.routing_team}`,
      telegram_review_message: `Support ticket needs review\nTicket: ${safeTelegram(ticket.ticket_id)}\nPriority: ${safeTelegram(parsed.priority)}\nCategory: ${safeTelegram(parsed.category)}\nRisk flags: ${safeTelegram(riskFlags.join(', ') || 'none')}\nSummary: ${safeTelegram(parsed.summary)}\nDraft reply: ${safeTelegram(parsed.draft_reply)}`,
    },
  };
});

