const SYSTEM_MESSAGE = `You are a support ticket triage assistant. You classify incoming customer support tickets and produce safe draft replies for a human support team.

Rules:
- Return JSON only.
- Do not include Markdown.
- Do not include explanations outside the JSON object.
- Use only the allowed categories, priorities, sentiments, routing teams, and risk flags.
- Do not promise refunds, cancellations, account deletion, compensation, legal outcomes, or security conclusions.
- Do not ask for passwords, full payment card numbers, secret keys, or private tokens.
- The draft reply is only for human review and must not claim that an action has already been completed.
- If intent is unclear, choose other, set needs_human_review to true, include unclear_intent, and use confidence below 0.75.

Allowed categories: billing, technical_issue, account_access, refund_request, cancellation, sales_question, complaint, other.
Allowed priorities: low, normal, high, urgent.
Allowed sentiments: positive, neutral, worried, angry, unclear.
Allowed routing teams: billing, technical_support, account_support, sales, support_lead.
Allowed risk flags: refund, payment_issue, account_deletion, legal_threat, security_issue, angry_customer, unclear_intent, low_llm_confidence, cancellation, manager_requested.`;

const schemaExample = {
  category: 'billing',
  priority: 'high',
  sentiment: 'angry',
  summary: 'Customer was charged twice and asks for refund.',
  routing_team: 'billing',
  needs_human_review: true,
  risk_flags: ['refund', 'angry_customer'],
  draft_reply: 'Short safe draft reply for human review.',
  confidence: 0.86,
};

return items.map((item) => {
  const ticket = item.json || {};
  const payload = ticket.llm_payload || {
    ticket_id: ticket.ticket_id,
    created_at: ticket.created_at,
    channel: ticket.channel,
    subject: ticket.subject,
    message: ticket.message,
    account_id: ticket.account_id,
    order_id: ticket.order_id,
    locale: ticket.locale,
    attachments_count: ticket.attachments_count,
  };

  const userMessage = [
    'Classify this support ticket.',
    '',
    'Ticket JSON:',
    JSON.stringify(payload, null, 2),
    '',
    'Escalation rules: needs_human_review must be true for refund request, angry customer, payment issue, account deletion, legal threat, security issue, unclear intent, cancellation request, or confidence below 0.75.',
    '',
    'Return exactly one JSON object using this schema:',
    JSON.stringify(schemaExample, null, 2),
  ].join('\n');

  return {
    json: {
      ...ticket,
      llm_provider: 'deepseek',
      llm_model: 'deepseek-chat',
      deepseek_request_body: {
        model: 'deepseek-chat',
        temperature: 0.1,
        max_tokens: 800,
        response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: SYSTEM_MESSAGE },
          { role: 'user', content: userMessage },
        ],
      },
    },
  };
});

const requestItems = $('Build DeepSeek request').all();
const text = (value) => String(value ?? '').trim();

function parseBody(value) {
  if (typeof value !== 'string') return value;
  try {
    return JSON.parse(value);
  } catch (_) {
    return value;
  }
}

function cleanModelText(value) {
  let output = text(value);
  output = output.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim();
  return output;
}

return items.map((item, index) => {
  const original = requestItems[index]?.json || {};
  const response = item.json || {};
  const statusCode = Number(response.statusCode || response.status || 200);
  const body = parseBody(response.body ?? response);
  const apiError = body?.error?.message || body?.message || response.error || '';
  const content = cleanModelText(body?.choices?.[0]?.message?.content || body?.choices?.[0]?.text || '');
  const ok = statusCode >= 200 && statusCode < 300 && content;

  return {
    json: {
      ...original,
      llm_provider: 'deepseek',
      llm_model: original.llm_model || 'deepseek-chat',
      llm_http_status: statusCode,
      llm_response_text: ok ? content : '',
      llm_error: ok ? '' : text(apiError || `DeepSeek returned no usable content, status ${statusCode}`),
    },
  };
});
